class Solution {
public:
    int countWinningSequences(string s) {
        const int MOD = 1e9 + 7;
        int n = s.size();
        vector<vector<int>> dp(n + 1, vector<int>(3, 0));
        dp[0][0] = dp[0][1] = dp[0][2] = 1;

        for (int i = 1; i <= n; i++) {
            char c = s[i - 1];
            vector<vector<int>> nextDp(n + 1, vector<int>(3, 0));
            for (int prev : {0, 1, 2}) {
                for (int curr : {0, 1, 2}) {
                    if (prev == curr) continue;
                    int points = getPoints(c, prev == 0 ? 'F' : (prev == 1 ? 'W' : 'E'));
                    int opponentPoints = getPoints('F' == c ? 'E' : ('W' == c ? 'F' : 'W'), curr == 0 ? 'F' : (curr == 1 ? 'W' : 'E'));
                    if (points < opponentPoints) {
                        nextDp[i][curr] = (nextDp[i][curr] + dp[i - 1][prev]) % MOD;
                    }
                }
            }
            dp = nextDp;
        }

        return (dp[n][0] + dp[n][1] + dp[n][2]) % MOD;
    }

    int getPoints(char a, char b) {
        if (a == 'F' && b == 'E') return 1;
        if (a == 'W' && b == 'F') return 1;
        if (a == 'E' && b == 'W') return 1;
        return 0;
    }
};
